import { useState } from "react";

const flash_sheet = require("./flash_sheet.jpg");
const red_x = require("./stock_red_x.jpg");

function placeRedX() {}


const handleClick = (event: React.MouseEvent<HTMLDivElement, MouseEvent>) => {
  const [clickLocations, setLocations] = useState<Array<Array<number>>>([]);
  let currentTargetRect = event.currentTarget.getBoundingClientRect();
  const event_offsetX = event.pageX - currentTargetRect.left,
        event_offsetY = event.pageY - currentTargetRect.top;
  setLocations((locs) => locs.concat([[event_offsetX, event_offsetY]]));
};

function FlashPage() {
  return (
    <div>
      <img src={flash_sheet} onClick={(event) => handleClick(event)}/>
      <p>
        {clickLocations}
      </p>
    </div>
  );
}

export default FlashPage;
